#!/usr/bin/env python3
"""Apple source-shape hygiene gate.

Enforces UI/design invariants by scanning the Apple app's own source files for
required and forbidden literal fragments (typography tokens instead of bare
SwiftUI text styles, calm empty-state panels instead of default chrome, inline
header controls, and so on). These are repository-source-hygiene assertions, so
they live in the verification gate rather than the Swift unit suite: keeping them
out of ``swift test`` means the Apple test run never has to walk source trees.

One rule additionally scans the whole monorepo -- including ``apps/tauri`` -- to
confirm a removed capture feature has not returned in any production source. That
cross-tree scan is deliberately tolerant of an absent or relocated Tauri tree (it
skips missing roots with a note) so the Apple gate never hard-depends on the
Tauri layout, honoring the root CLAUDE.md rule of zero coupling between the apps.

Exit status: 0 when every invariant holds, 1 otherwise (offending file plus the
missing/forbidden fragment are printed to stderr).
"""
from __future__ import annotations

import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]   # apps/apple
REPO = ROOT.parents[1]                         # monorepo root

TOKEN_SCAN_ROOTS = [
    "apps/apple/Sources",
    "apps/apple/core/Sources",
    "schema",
    "apps/tauri/app/src",
    "apps/tauri/app/src-tauri/src",
    "apps/tauri/lorvex-store/src",
    "apps/tauri/lorvex-workflow/src",
    "apps/tauri/mcp-server/src",
    "apps/tauri/cloudkit",
]
TOKEN_SCAN_EXTENSIONS = {"swift", "rs", "ts", "tsx", "sql", "json", "ckdb"}
# Assembled from fragments so this gate file does not itself carry the literal.
FORBIDDEN_TOKEN = "".join(["sc", "rat", "ch", "pa", "d"])

# Each rule is a tuple. Scopes:
#   ("file", relpath)            one file, relative to apps/apple
#   ("join", [relpath, ...])     files concatenated with "\n"
#   ("dir", reldir, recursive)   applied to each .swift file under a dir
# Rule kinds:
#   ("contains", scope, literal)      scope must contain literal
#   ("absent", scope, literal)        scope must NOT contain literal
#   ("count_ge", scope, literal, n)   literal occurs at least n times
#   ("order", ("file", p), a, b)      a appears before b in the file
#   ("file_missing", relpath)         file must NOT exist (relative to apps/apple)
#   ("tree_absent_token",)            the cross-tree FORBIDDEN_TOKEN scan
