_CACHE: dict[str, str | None] = {}


def _read(relpath: str) -> str | None:
    if relpath not in _CACHE:
        try:
            _CACHE[relpath] = (ROOT / relpath).read_text(encoding="utf-8")
        except (FileNotFoundError, IsADirectoryError):
            _CACHE[relpath] = None
    return _CACHE[relpath]


def _scope_texts(scope) -> list[tuple[str, str]]:
    kind = scope[0]
    if kind == "file":
        text = _read(scope[1])
        if text is None:
            raise FileNotFoundError(scope[1])
        return [(scope[1], text)]
    if kind == "join":
        parts = []
        for rel in scope[1]:
            text = _read(rel)
            if text is None:
                raise FileNotFoundError(rel)
            parts.append(text)
        return [("+".join(scope[1]), "\n".join(parts))]
    if kind == "dir":
        rel, recursive = scope[1], scope[2]
        base = ROOT / rel
        if not base.is_dir():
            raise FileNotFoundError(rel)
        it = base.rglob("*.swift") if recursive else base.glob("*.swift")
        return [(str(f.relative_to(ROOT)), f.read_text(encoding="utf-8")) for f in sorted(it)]
    raise ValueError(f"unknown scope {scope!r}")


def token_scan_failures() -> list[str]:
    failures: list[str] = []
    for rel in TOKEN_SCAN_ROOTS:
        base = REPO / rel
        if not base.is_dir():
            print(f"note: source-hygiene token scan skips missing root {rel}", file=sys.stderr)
            continue
        for path in sorted(base.rglob("*")):
            if path.is_dir():
                continue
            if path.suffix.lstrip(".").lower() not in TOKEN_SCAN_EXTENSIONS:
                continue
            relpath = path.relative_to(REPO).as_posix()
            if FORBIDDEN_TOKEN in relpath.lower():
                failures.append(f"removed capture feature returned (path): {relpath}")
                continue
            try:
                body = path.read_text(encoding="utf-8")
            except (UnicodeDecodeError, OSError):
                continue
            if FORBIDDEN_TOKEN in body.lower():
                failures.append(f"removed capture feature returned (content): {relpath}")
    return failures


def source_hygiene_failures(rules=RULES) -> list[str]:
    failures: list[str] = []
    for rule in rules:
        kind = rule[0]
        try:
            if kind == "tree_absent_token":
                failures.extend(token_scan_failures())
            elif kind == "file_missing":
                if (ROOT / rule[1]).exists():
                    failures.append(f"file must not exist: {rule[1]}")
            elif kind == "contains":
                for label, text in _scope_texts(rule[1]):
                    if rule[2] not in text:
                        failures.append(f"{label}: missing required fragment {rule[2]!r}")
            elif kind == "absent":
                for label, text in _scope_texts(rule[1]):
                    if rule[2] in text:
                        failures.append(f"{label}: forbidden fragment present {rule[2]!r}")
            elif kind == "count_ge":
                for label, text in _scope_texts(rule[1]):
                    got = text.count(rule[2])
                    if got < rule[3]:
                        failures.append(f"{label}: fragment {rule[2]!r} occurs {got}x, need >= {rule[3]}")
            elif kind == "count_eq":
                for label, text in _scope_texts(rule[1]):
                    got = text.count(rule[2])
                    if got != rule[3]:
                        failures.append(f"{label}: fragment {rule[2]!r} occurs {got}x, need == {rule[3]}")
            elif kind == "order":
                (label, text), = _scope_texts(rule[1])
                bi, ai = text.find(rule[2]), text.find(rule[3])
                if bi < 0:
                    failures.append(f"{label}: missing {rule[2]!r}")
                elif ai < 0:
                    failures.append(f"{label}: missing {rule[3]!r}")
                elif bi >= ai:
                    failures.append(f"{label}: {rule[2]!r} must appear before {rule[3]!r}")
            else:
                raise ValueError(f"unknown rule kind {kind!r}")
        except FileNotFoundError as exc:
            failures.append(f"required source file missing: {exc}")
    return failures


def main() -> int:
    failures = source_hygiene_failures()
    if failures:
        print("Apple source hygiene verification failed:", file=sys.stderr)
        for failure in failures:
            print(f"- {failure}", file=sys.stderr)
        return 1
    print("Apple source hygiene verification passed")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
